"use client";

// HQAdz wordmark (glow logo). The PNG is inlined as a data URI so there is no
// standalone URL to open in a new tab or download, and the element is
// pointer-events-none + non-draggable + non-selectable so users can't right-click
// "save image". The dark background was removed (luminance->alpha) so the glow
// composites cleanly on any dark surface.
// `height` is the FULL box height incl. glow; the letters are ~64% of it, so a
// box height of ~30 reads like ~19px text next to it.
const SRC =
  "data:image/png;base64,";

const RATIO = 4.306; // 775 x 180

export default function BrandMark({
  height = 30,
  className = "",
}: {
  height?: number;
  className?: string;
}) {
  return (
    <span
      role="img"
      aria-label="HQAdz"
      onContextMenu={(e) => e.preventDefault()}
      onDragStart={(e) => e.preventDefault()}
      className={`inline-block select-none pointer-events-none bg-no-repeat bg-contain bg-center ${className}`}
      style={{
        height,
        width: height * RATIO,
        backgroundImage: `url(${SRC})`,
        WebkitUserSelect: "none",
        userSelect: "none",
      }}
    />
  );
}
